import{_ as a,o as t,c as p,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"龙象般若功","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/龙象般若功.md","filePath":"4.资源分区/6.技艺及称号/武技类/肉搏类/龙象般若功.md"}'),b={name:"4.资源分区/6.技艺及称号/武技类/肉搏类/龙象般若功.md"};function o(d,e,_,l,i,c){return t(),p("div",null,[...e[0]||(e[0]=[r("h1",{id:"龙象般若功",tabindex:"-1"},[n("龙象般若功 "),r("a",{class:"header-anchor",href:"#龙象般若功","aria-label":'Permalink to "龙象般若功"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调015")])])],-1),s('<h1 id="龙象般若功-1" tabindex="-1">龙象般若功 <a class="header-anchor" href="#龙象般若功-1" aria-label="Permalink to &quot;龙象般若功&quot;">​</a></h1><p>龙象般若功<br> 出自《泛金庸武侠》系列，原记载于龙象般若经上，为密宗里至高无上的护法神功，纵是下愚之人亦可修成。<br> 但修炼起来极为耗费时间，理论上需千年才能达到最高境界，故被后人将十三层整理为五层，以完善至接近【龙象般若】的境界。</p><p>般若境界<br> 描述：般若空慧，至坚至利，断诸众生难断之惑，是洞见一切本相的终极智慧而抵达的境界，虽然并非觉悟者无法抵达这一境界，但随着对于心性境界的领悟，该技艺带来的力量也会有所增长。<br> 五层境界分别为：尘、逡巡、刹那、阿摩罗、涅槃寂静，依次购买解锁对应效果，每次购买价格为1C+2000。</p><p>龙象境界<br> 价格：C+1000<br> 描述：“龙象威势，吐纳如鲸，心跳如山鸣，握铁如浆，溅血碎石。”<br> 效果：消耗一个标准动作，本轮内你在力量上获得10DP的加值。<br> 你你在消耗这个标准动作时，可以同时进行一次不附带招式的以力量为关键属性的攻击，并可以在这次攻击中选择将获得的力量加值转换为等量的【破甲】。</p><p>金刚境界<br> 价格：C+2000<br> 描述：“坚固不移，至坚至利，能断难断，能碎万物，譬喻般若空慧。”<br> 效果：消耗一个移动动作，直到下一轮你的回合开始前，你在天生防御上获得10DP的加值。<br> 你在消耗移动动作使用金刚境界时，可以同时进行一次移动。<br> 当你使用金刚境界后，你在执行龙象般若功的攻击时，可以选择将金刚境界提供的天生防御等量的转换为【威猛】，转换后需要重新启动才能再次获得提供的天生防御。</p><p>尘：购买后解锁。<br> 你在执行龙象境界的攻击时，获得【湮灭】特性。</p><p>你在获得金刚境界带来的防御时，立刻获得基于天生防御的【适应】【坚韧】特性，使用动作下降为迅捷动作，转换为威猛时也无需移动，只要在持续时内随时可以转换。</p><p>逡巡：<br> 你在执行龙象境界的攻击时，攻击获得【8加骰】特性。<br> 你在获得金刚境界带来的防御时，获得免疫接触攻击与基于天生防御的【防能量武器】特性。</p><p>刹那：<br> 你在每回合开始时获得2点只能使用龙象境界或者金刚境界的AP。<br> 你在执行一次龙象境界的攻击时，可以选择不立刻进行攻击，当本轮内你受到攻击时，若你可以攻击到该敌方单位，可以一个反射动作打断性的对攻击者发起攻击，这次攻击具有C级【先制】效果，每个回合只能使用这个效果一次。<br> 若如此做，你的这次攻击默认还会执行一次冲撞，以攻击伤害值与对方进行对抗，自行选择击退还是击倒。</p><p>你在获得金刚境界带来的防御时，免疫冲击点数带来的减值，同时获得基于天生防御的【防弹】，你的基础防御类型将转为天生防御。<br> 若你已有任意快速医疗效果，则选择其中一个增加1点快速医疗和12点治疗点。</p><p>阿摩罗：<br> 你在执行一次龙象境界的攻击时，本次龙象境界提供的力量加值提升到15点，同时直接获得5点无需转换的破甲，能够使攻击落点的3米范围内所有敌人同时承受本次攻击。</p><p>你在获得金刚境界带来的防御时，本次金刚境界提供的防御加值提升至15点，同时获得5点的抵破甲，以及免疫C级影响心灵来源的负面效果。</p><p>涅槃寂静：<br> 作为最高境界，暂不提供购买渠道。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',15)])])}const m=a(b,[["render",o]]);export{f as __pageData,m as default};
